def activitySelection(start, finish):
    # WRONG: Sorting by start time instead of finish time
    activities = sorted(zip(start, finish), key=lambda x: x[0])

    count = 0
    last_end_time = -1

    for s, f in activities:
        if s >= last_end_time:
            count += 1
            last_end_time = f
    return count
